package exams

import (
	"fmt"
	"math/rand"
)

// Question is the shape returned to the frontend for both AI-generated and
// offline-bank questions — matches server/ai.js / server/exams.js's output.
type Question struct {
	ID           string   `json:"id"`
	Domain       string   `json:"domain"`
	Scenario     string   `json:"scenario"`
	Question     string   `json:"question"`
	Options      []string `json:"options"`
	CorrectIndex int      `json:"correctIndex"`
	Explanation  string   `json:"explanation"`
}

// bankItem mirrors server/exams.js's QUESTION_BANK shorthand ({d,q,s,o,c,e}).
type bankItem struct {
	Domain       string
	Scenario     string
	Question     string
	Options      [4]string
	CorrectIndex int
	Explanation  string
}

