// SampleQuestions ports server/exams.js's sampleQuestions: a random subset
// (shuffle, then take min(count, len)) of the offline bank for examType.
func SampleQuestions(examType string, count int) []Question {
	bank := questionBank[examType]
	shuffled := make([]bankItem, len(bank))
	copy(shuffled, bank)
	rand.Shuffle(len(shuffled), func(i, j int) { shuffled[i], shuffled[j] = shuffled[j], shuffled[i] })

	n := count
	if n > len(shuffled) {
		n = len(shuffled)
	}
	out := make([]Question, n)
	for i, item := range shuffled[:n] {
		out[i] = Question{
			ID:           fmt.Sprintf("q%d", i+1),
			Domain:       item.Domain,
			Scenario:     item.Scenario,
			Question:     item.Question,
			Options:      item.Options[:],
			CorrectIndex: item.CorrectIndex,
			Explanation:  item.Explanation,
		}
	}
	return out
}
